var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"오랜만이야, 길고양이.","JPN":"久しぶりだね、野良猫。","ENG":"Long time no see, stray cat.","TWN":"好久不見了，流浪貓。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 이렇게 혼잣말하고 있으니까 조금 부끄러운데?","JPN":"ふふ、独り言だなんて、ちょっと恥ずかしいわね。","ENG":"Fu fuu, I feel a little embarrassed talking to myself like this.","TWN":"呵呵，這樣自言自語，我自己都覺得有點不好意思。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"아, 눈치챘으려나? 이 레코더 쥐스틴이 맨날 가지고 다니던 거야.","JPN":"あ、気付いたかな？　このレコーダー、ジュスティーヌがいつも持っていたものなの。","ENG":"Oh, did you notice? This is the recorder that Justine always carried around.","TWN":"喔，你注意到了嗎？這是潔絲婷以前一直隨身攜帶的相機。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"네 흑역사가 잔뜩 담겨 있는 물건이기도 하고.","JPN":"あなたの黒歴史がたくさん入ってるものでもあるのよ。","ENG":"It's also the thing that holds all of your embarrassing moments.","TWN":"裡面保存了很多你的黑歷史。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그리고 이젠 너에 대한 기록이 남아 있는……. 몇 안 되는 물건이기도 하지…….","JPN":"そして、あなたの記録が残された……数少ないものの一つでもあるの……","ENG":"But most of all, it's one of the few items... that holds any record of you...","TWN":"也是現在關於你……為數不多的記錄之一。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이 목소리가 너에게 닿을 일은 없겠지만.","JPN":"この声があなたに届くことはないでしょうけど。","ENG":"I know my voice will never reach you.","TWN":"雖然這些記錄無法再傳達到你那裡。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"나는 닿지 않으면, 닿지 않는 대로 괜찮다고 생각해.","JPN":"私はそれでもいいと思う。","ENG":"But I think it's okay even if it doesn't.","TWN":"但我認為已經足夠了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"20년이라는 시간이 흘렀다고 하더라?","JPN":"もう20年も経つんだって。","ENG":"Twenty years have passed since that day.","TWN":"快20年了吧？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"내가 잠들었던 사이에, 그리고 네가 없는 사이에.","JPN":"私が眠っていた間に、そしてあなたがいない間に。","ENG":"While I was asleep and you gone.","TWN":"當我沉睡時，而你也不在時。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"시간이 참 빠르지? 그동안 많은 일이 있었다고 하더라고.","JPN":"時間って早いものね。その間に、色んなことがあったみたいよ。","ENG":"Time goes by so fast, right? I heard a lot has happened in the meantime.","TWN":"時間過得真快，不是嗎？這期間發生了很多事情。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그 중에 가장 충격적이었던 건, 원래 관리국이 망하고 새로운 관리국이 출범했다는 거야.","JPN":"中でも一番衝撃だったのは、私たちの知る管理局が滅びて、新しい管理局が設立されたの。","ENG":"The most shocking news of all was that the Administration had failed and a new Administration was established.","TWN":"其中最讓我震驚的是，舊管理局的結束，和新管理局的誕生。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그 대단한 관리국이 이렇게 속절없이 망해버릴 줄이야.","JPN":"あのすごい管理局がこんなに虚しく滅んじゃうなんてね。","ENG":"Who knew that the great Administration would go down like that, right?","TWN":"沒想到那個強大的管理局會在一瞬間覆滅。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그럼 우리는 대체 뭘 위해서 싸웠던 걸까?","JPN":"じゃあ、私たちはいったい何のために戦ってたのかな。","ENG":"It makes me wonder what we were fighting for.","TWN":"而我們又是為了什麼而戰？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그리고 나는 너에게 뭘 강요했던 걸까?","JPN":"そして、私はあなたに何を強要したんだろう。","ENG":"And also what I was trying to force upon you.","TWN":"之前的我是否在強迫你？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이젠, 잘 모르겠어.","JPN":"もう、わからないの。","ENG":"Now, I'm not so sure.","TWN":"我現在，不確定了。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그 날 일은 생생하게 기억나지는 않아.","JPN":"あの日のことは、はっきりと思い出せない。","ENG":"To be honest, I don't remember much about that day.","TWN":"那天的事情，我已記不太清了。"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"멘탈프린팅에 의한 정신 오염은 부분적인 기억 소거로 완화할 수 있다고 하거든.","JPN":"メンタル・プリンティングによる精神汚染は、部分的な記憶消去で緩和できるんだって。","ENG":"People have told me that partial memory erasure can alleviate some of the mental contamination caused by Mental Printing.","TWN":"智力複印引起的精神污染可以透過消除部分記憶來緩解。"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그리고 얼어 있는 동안 약해진 몸을 재활치료 하는 데도 꽤 오랜 시간이 걸려 버렸지.","JPN":"それに、凍っている間に弱くなった体をリハビリするのにも結構時間がかかってしまったわ。","ENG":"It also took a long time to rehabilitate my weakened body that had been frozen.","TWN":"我的身體在冷凍期間變得虛弱，這花了我很長時間來進行身體恢復。"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"후후, 너무 걱정하지마. 지금은 많이 나아졌으니까.","JPN":"ふふ、あまり心配しないで。今はだいぶ良くなったから。","ENG":"Fu fuu, but don't worry. I'm better now.","TWN":"呵呵，不過不用太擔心。現在已經好得差不多了。"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"줄곧 난 너한테 사과해야 한다고 생각했어.","JPN":"私はずっとあなたに謝らないとって思っていたの。","ENG":"I've always thought that I needed to apologize to you.","TWN":"一直以來，我都覺得應該對你說聲對不起。"},"stage":{"bg":"YAKSHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"너를 위해서라고 멋대로 단정짓고 저질렀던 일들이…….","JPN":"あなたのためを思ってやったことが……","ENG":"All those things I did, assuming that it was all for you...","TWN":"就算是為了你，我所做的事還是太過武斷了……"},"stage":{"bg":"YAKSHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"돌고 돌아서 결국, 너를 그렇게 만든 거나 다름없으니까.","JPN":"巡り巡って結局、あなたを滅ぼすことになってしまったわ。","ENG":"They ended up making you like that, in the end","TWN":"繞了一大圈下來，最終還是因為我，才讓你變成了這樣。"},"stage":{"bg":"YAKSHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"너라면 분명 웃으면서 별것 아니라고 하겠지만, 나는 책임져야 한다고 생각해.","JPN":"あなたならきっと笑いながら大したことないって言うんでしょうけど、私はその責任を負うべきだと思う。","ENG":"I'm sure you'd just brush it off and laugh about it, but I think I need to take on the responsibility.","TWN":"我很確定如果你還在旁邊，肯定會笑說這沒什麼大不了的，但我想我必須承擔起這個責任。"},"stage":{"bg":"YAKSHA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"이제 이 세상에 널 기억하는 사람은 많지 않지만.","JPN":"もうこの世界にあなたを記憶する人は多くないけれど、","ENG":"Now, there aren't a lot of people who remember you.","TWN":"現在，這個世界上已經沒有多少人記得你了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"네가 구해준 나와 전대원들은 절대 너를 잊지 않을 거야.","JPN":"あなたが救ってくれた私と戦隊員は、絶対あなたのことを忘れない。","ENG":"But me and the other members you saved will never forget about you.","TWN":"但我和你救下的戰隊員永遠不會忘記你。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"야크샤의 일원으로서 우리는 계속 네 의지를 이어갈 거야.","JPN":"ヤクシャーの一員として、私たちはあなたの意志を受け継ぎ続けるわ。","ENG":"As a member of the Yaksha Division, we will continue to carry on your will.","TWN":"作為夜叉的一員，我們將繼續執行你的意志。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RABBIT_YAKSHA_NULL_NULL","text":{"KOREA":"그러기 위해서, 우리가 가장 먼저 시작한 일은…….","JPN":"そのために、私たちが一番に始めたのが……","ENG":"And to do that, the first thing we started with was...","TWN":"為此，我們首先要做的就是……"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};